import { useEffect, useRef, useState } from "react";
import { preprocessWordList } from "./lib/dictionary";
import { keepHebrewLetters, normalizeFinalLetters, restoreFinalLettersForDisplay } from "./lib/hebrew";
import { findMultiWordAnagrams, type MultiWordResult } from "./lib/multiwordAnagrams";
import "./yuval.css";

const DICT_URL = `${import.meta.env.BASE_URL}hebrew_dict.txt`;

type DictState =
  | { status: "loading" }
  | { status: "ready"; words: string[] }
  | { status: "error" };

function normalize(s: string): string {
  return normalizeFinalLetters(keepHebrewLetters(s));
}

export default function YuvalApp() {
  const [dict, setDict] = useState<DictState>({ status: "loading" });
  const [input, setInput] = useState("");
  const [results, setResults] = useState<MultiWordResult[]>([]);
  const [searched, setSearched] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    fetch(DICT_URL)
      .then((r) => r.text())
      .then((raw) => setDict({ status: "ready", words: preprocessWordList(raw) }))
      .catch(() => setDict({ status: "error" }));
  }, []);

  function handleSearch() {
    if (dict.status !== "ready") return;
    const letters = normalize(input);
    if (!letters) return;
    inputRef.current?.blur();
    const combos = findMultiWordAnagrams(letters, dict.words, { minWords: 1 });
    const identity = letters;
    setResults(combos.filter((c) => c.words.join("") !== identity));
    setSearched(true);
  }

  function handleKey(e: React.KeyboardEvent<HTMLInputElement>) {
    if (e.key === "Enter") handleSearch();
  }

  return (
    <div className="yuval-app">
      {/* Dedication */}
      <header className="dedication">
        <div className="dedication__ornament">❦</div>
        <h1 className="dedication__to">לכבוד</h1>
        <h2 className="dedication__name">יובל כפיר</h2>
        <p className="dedication__body">
          האח הטוב ביותר שיכולתי לאחל לעצמי
        </p>
        <div className="dedication__ornament dedication__ornament--bottom">❦</div>
      </header>

      {/* Divider */}
      <div className="divider">
        <span className="divider__line" />
        <span className="divider__text">מחולל האנגרמות</span>
        <span className="divider__line" />
      </div>

      {/* Search */}
      <main className="yuval-search">
        <div className="yuval-input-row">
          <input
            ref={inputRef}
            className="yuval-input"
            type="text"
            inputMode="text"
            placeholder="הקלידו אותיות בעברית…"
            value={input}
            onChange={(e) => { setInput(e.target.value); setSearched(false); setResults([]); }}
            onKeyDown={handleKey}
            aria-label="אותיות לחיפוש"
            disabled={dict.status === "loading"}
          />
          <button className="yuval-btn" onClick={handleSearch} disabled={dict.status !== "ready" || !normalize(input)}>
            {dict.status === "loading" ? "טוען…" : "חפש"}
          </button>
        </div>

        {dict.status === "error" && (
          <p className="yuval-status yuval-status--error">טעינת המילון נכשלה</p>
        )}

        {searched && results.length === 0 && (
          <p className="yuval-status">לא נמצאו צירופים מהאותיות האלה</p>
        )}

        {results.length > 0 && (
          <div className="yuval-results">
            <p className="yuval-results__count">{results.length.toLocaleString("he-IL")} צירופים</p>
            <ul className="yuval-results__list">
              {results.map((combo, i) => (
                <li key={i} className="yuval-results__item">
                  {combo.words.map((w: string) => restoreFinalLettersForDisplay(w)).join(" · ")}
                </li>
              ))}
            </ul>
          </div>
        )}
      </main>

      <footer className="yuval-footer">
        <a href="../" className="yuval-footer__back">← לאפליקציה הראשית</a>
      </footer>
    </div>
  );
}
